async function refreshActivitySummaries() {
  try {
    const summaries = await GetWorkspaceActivitySummaries();
    const map = new Map<string, services.WorkspaceActivitySummary>();
    for (const s of summaries) {
      map.set(s.workspaceId, s);
    }
