  const dataUrl = btn.dataset.imageUrl ?? "";

  if (!dataUrl) return;

  // Desktop (Wails): call backend SaveChatImageToDisk for native save dialog + file write
  if (isWebMode()) {
    // Web mode: use browser-native download via <a> element trick
    const link = document.createElement("a");
    link.href = dataUrl;
    link.download = name;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  } else {
    // Desktop mode: use backend method for native save dialog
    SaveChatImageToDisk(workspace?.id ?? "", {
      name,
      mediaType,
      dataUrl,
    }).then((savedPath) => {
      if (savedPath) {
        pushToast({ message: `Saved to ${savedPath}`, type: "success" });
      }
      // If savedPath is empty string, user canceled the dialog — no toast needed.
    }).catch(() => {
      // Fallback to browser download on error
      const link = document.createElement("a");
      link.href = dataUrl;
      link.download = name;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    });
  }
}
```

### `frontend/src/backend/services.ts`

Add wrapper:
```typescript
export function SaveChatImageToDisk(...args: Parameters<typeof Wails.SaveChatImageToDisk>): ReturnType<typeof Wails.SaveChatImageToDisk> {
  return call("SaveChatImageToDisk", Wails.SaveChatImageToDisk, args);
}
```

